    MEDIUM = "medium"            # 256 kbps, standard content
    HIGH = "high"                # 512 kbps, rich content
    ULTRA_HIGH = "ultra_high"    # 1+ Mbps, premium content
    ADAPTIVE = "adaptive"        # Dynamic based on conditions

